mapper.select:
/* com.erns.coching.board.mapper.BoardMasterDAO.getList */
SELECT B.* FROM ( SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM ( SELECT
, , CC.CODE_NAME AS BOARD_TYPE_NM FROM T_BOARD_MST AA LEFT OUTER JOIN T_BOARD_OPT BB ON AA.BOARD_MST_ID = BB.BOARD_MST_ID INNER JOIN T_CODE_INF CC ON AA.BOARD_TYPE = CC.CODE AND CC.GRP_CODE ='CH005'
ORDER BY AA.BOARD_MST_ID ) A ) B
WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

/* com.erns.coching.board.mapper.BoardMasterDAO.load */

SELECT

	, 
FROM T_BOARD_MST AA
LEFT OUTER JOIN T_BOARD_OPT BB ON AA.BOARD_MST_ID = BB.BOARD_MST_ID

	AA.BOARD_MST_ID = #{boardMstId, jdbcType=VARCHAR}

mapper.insert:
    	/* com.erns.coching.board.mapper.BoardMasterDAO.insert */
    	INSERT INTO T_BOARD_MST (
    		  BOARD_MST_ID
			, BOARD_NAME
			, BOARD_TYPE
			, BOARD_DESC
			, USE_YN

			, RGTR
			, RGT_DTTM
			, CHNR
			, CHNG_DTTM
    	) VALUES (
    		  #{boardMstId	, jdbcType=VARCHAR}
			, #{boardName	, jdbcType=VARCHAR}
			, #{boardType	, jdbcType=VARCHAR}
			, #{boardDesc	, jdbcType=VARCHAR}
			, COALESCE(#{useYn	, jdbcType=CHAR}, 'Y')

			, #{rgtr		, jdbcType=INTEGER}
			, now()
			, #{chnr		, jdbcType=INTEGER}
			, now()
    	)

mapper.update:
    	/* com.erns.coching.board.mapper.BoardMasterDAO.update */
    	UPDATE T_BOARD_MST SET
			  BOARD_NAME  = #{boardName, jdbcType=VARCHAR}
			, BOARD_TYPE  = #{boardType, jdbcType=VARCHAR}
			, BOARD_DESC  = #{boardDesc, jdbcType=VARCHAR}
			, USE_YN  	  = COALESCE(#{useYn, jdbcType=CHAR}, 'Y')

			, CHNR		  = #{chnr	   , jdbcType=INTEGER}
			, CHNG_DTTM	  = now()

			BOARD_MST_ID  = #{boardMstId, jdbcType=VARCHAR}

    	/* com.erns.coching.board.mapper.BoardMasterDAO.updateUseYn */

    	UPDATE T_BOARD_MST SET
			  USE_YN            = COALESCE(#{useYn	, jdbcType=CHAR}, 'N')

			, CHNR 		 	= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM  	= now()

			AND BOARD_MST_ID  = #{boardMstId, jdbcType=VARCHAR}

    	/* com.erns.coching.board.mapper.BoardMasterDAO.updateState */

    	UPDATE T_BOARD_MST SET
			  USE_YN            = COALESCE(#{useYn	, jdbcType=CHAR}, 'N')

			, CHNR 		 	= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM  	= now()

			AND BOARD_MST_ID  = #{boardMstId, jdbcType=VARCHAR}

mapper.delete:
/* com.erns.coching.board.mapper.BoardMasterDAO.delete */

DELETE FROM T_BOARD_MST

	AND BOARD_MST_ID = #{boardMstId, jdbcType=VARCHAR}
